func copyFile(dst, src string) error {
    s, err := os.Open(src)
    if err != nil { return err }
    defer s.Close()
    d, err := os.OpenFile(dst, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o640)
    if err != nil { return err }
    defer d.Close()
    _, err = io.Copy(d, s)
    return err
}

char *safe_copy(const char *src) {
    if (!src) return NULL;
    size_t n = strlen(src);
    char *dst = malloc(n + 1);
    if (dst) memcpy(dst, src, n + 1);
    return dst;
}

int validate_int(const char *s, int *out) {
    char *end;
    long v = strtol(s, &end, 10);
    if (*end || v < INT_MIN || v > INT_MAX) return -1;
    *out = (int)v;
    return 0;
}

