int safe_strcmp(const char *a, const char *b, size_t maxlen) {
    unsigned char result = 0;
    for (size_t i = 0; i < maxlen; i++) {
        result |= (unsigned char)a[i] ^ (unsigned char)b[i];
        if (!a[i] && !b[i]) break;
    }
    return result ? -1 : 0;
}

